<?php
namespace Tests\Feature;
use App\Models\{Checkin,Guest,HousekeepingTask,MaintenanceWorkOrder,Reservation,Room,User};use Illuminate\Foundation\Testing\RefreshDatabase;use Inertia\Testing\AssertableInertia as Assert;use Tests\TestCase;
class ReportsTest extends TestCase{use RefreshDatabase;
 public function test_manager_can_view_operational_metrics():void{$manager=User::factory()->create(['role'=>'manager']);$guest=Guest::create(['first_name'=>'Report','last_name'=>'Guest']);$room=Room::create(['number'=>'801','type'=>'Suite','floor'=>8,'status'=>'available','price'=>200]);Reservation::create(['guest_id'=>$guest->id,'room_id'=>$room->id,'reference'=>'RP-801','arrival_date'=>today(),'departure_date'=>today()->addDays(2),'status'=>'checked_in','payment_status'=>'partial','total_amount'=>400,'amount_paid'=>250,'source'=>'direct']);Checkin::create(['guest_id'=>$guest->id,'room_id'=>$room->id,'check_in_date'=>today()->subDay(),'check_out_date'=>today()->addDay(),'booking_reference'=>'RP-801','is_active'=>true]);HousekeepingTask::create(['room_id'=>$room->id,'status'=>'inspected','priority'=>'normal','started_at'=>now()->subMinutes(50),'completed_at'=>now()->subMinutes(20)]);MaintenanceWorkOrder::create(['room_id'=>$room->id,'title'=>'Repair lamp','description'=>'Lamp issue','status'=>'inspected','priority'=>'normal','started_at'=>now()->subMinutes(90),'repaired_at'=>now()->subMinutes(30),'cost'=>40]);$this->actingAs($manager)->get(route('dashboard.reports.index',['from'=>today()->subDays(7)->toDateString(),'to'=>today()->toDateString()]))->assertOk()->assertInertia(fn(Assert$page)=>$page->component('Dashboard/Reports/Reports')->where('summary.collected_revenue',250)->where('summary.outstanding_balance',150)->where('summary.maintenance_cost',40)->where('summary.average_cleaning_minutes',30)->has('trend',8));}
 public function test_front_desk_cannot_view_reports():void{$staff=User::factory()->create(['role'=>'front_desk']);$this->actingAs($staff)->get(route('dashboard.reports.index'))->assertForbidden();}
 public function test_super_admin_can_export_reports_csv():void{$admin=User::factory()->create(['role'=>'super_admin']);$this->actingAs($admin)->get(route('dashboard.reports.export'))->assertOk()->assertHeader('content-type','text/csv; charset=UTF-8')->assertDownload();}
}
